var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"모르가나 아가씨. 다들 출정 준비를 마쳤습니다.","JPN":"モルガナお嬢様。全員出征準備が整いました。","ENG":"Miss Morgana, everyone is ready to depart.","TWN":"莫甘娜小姐，大家都已經做好出征準備。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마차는 잘 수리된 거지? 아이단이랑 딜런은?","JPN":"馬車はちゃんと直ったのよね？　子どもたちとディランは？","ENG":"Is the carriage in good repair? What about Aidan and Dylan?","TWN":"馬車有修好吧？艾丹和狄倫呢？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"모두 정비를 마쳤습니다. 컨디션도 아주 좋고요.","JPN":"皆準備できています。調子も良好です。","ENG":"All maintenance is complete, and they are all in good condition.","TWN":"都已預備妥當，狀態也非常良好。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"좋아. 그럼 바로 출발을 하기 전에…","JPN":"よし、ではさっそく出発したいところだけど、その前に……","ENG":"All right. Then before we embark...","TWN":"好，那在出發前…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…넌 뭐야?","JPN":"……あなたは何しているの？","ENG":"...Lugh, what are you doing here?","TWN":"…你幹嘛？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"너라뇨, 모르가나. 앞으로는 언니라고 부르기로 약속했잖아요.","JPN":"あなたって何ですか、モルガナ。これからはお姉さんって呼ぶ約束でしたよね。","ENG":"\\"Lugh?\\" Morgana, you promised to call me Ms. Lugh, remember?","TWN":"你什麼你。莫甘娜，不是說好以後你要叫我姊姊嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아니… 그러니까…","JPN":"うっ……だから……","ENG":"Uh... I mean...","TWN":"可是…就是…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어, 언니.","JPN":"お、お姉さん。","ENG":"M-Ms. Lugh.","TWN":"姊…姊姊。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"방금 들었어? 아가씨가 다른 사람을 언니라고 부르다니.","JPN":"聞いたか？　お嬢様が他の人をお姉さんて呼んでるぞ。","ENG":"Did you hear that? Miss Morgana just called someone else with an honorific.","TWN":"大家有聽到嗎？小姐竟然叫別人姊姊欸？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"쉿, 저 표정 안 보여? 무조건 못 들은 척해.","JPN":"しっ、あの顔を見ろ、聞こえなかったふりをしておけ。","ENG":"Shh! Can't you see her expression? Act like you didn't hear a thing.","TWN":"噓！你沒看到小姐的表情嗎？我勸你最好裝沒聽到。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쨌거나!","JPN":"それはともかく！","ENG":"ANYWAY!","TWN":"總之！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"언니가 왜 조사단 출정 대열에 서있는 건데?","JPN":"お姉さんがどうして調査団の出征隊列に立っているのよ！","ENG":"Why are you in line for a survey corps expedition?","TWN":"姊姊為何會出現在調查團出征的隊伍裡？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"우리 조사단이 무슨 일을 하는지 알고는 있긴 한 거야?","JPN":"あたしたち調査団が何をするのか理解はしているの？","ENG":"Do you even know what we do?","TWN":"你知道調查團是在做什麼的嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"조사단은 그루터기의 연구를 돕기 위해 만들어진 조직이라고 들었어요.","JPN":"調査団は切り株の研究を助力するために結成した組織だと聞きました。","ENG":"I heard the Stump established the survey corps to assist with research.","TWN":"我聽說調查團這個組織，專門在協助木墩的研究。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"길잡이가 만든 관측기구로 귀한 자원인 적철이 있는 장소를 파악하고, 조사단은 동토를 가로질러서 그 적철을 구해오는 거죠.","JPN":"導き手が作った観測器具で貴重な資源である赤鉄のある場所を特定し、調査団は凍土を横断して赤鉄を回収して来るんですよね。","ENG":"They use observation tools made by pathfinders to locate areas with the precious material known as Violarite, and cross the gelid lands to retrieve them.","TWN":"你們會利用引路人製造的觀測工具來尋找珍貴的資源赤鐵，調查團主要的行動就是橫跨凍土收集赤鐵。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"잘 아네.","JPN":"ちゃんと理解してるじゃない。","ENG":"So, you do know.","TWN":"很清楚嘛。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이건 소꿉장난이 아니라 그루터기를 위해 목숨을 걸고 하는 일이야.","JPN":"これはお遊びじゃなくて、切り株のために命をかけて行うものよ。","ENG":"This isn't a game. We're all risking our lives for the Stump.","TWN":"這不是在開玩笑的，是要要木墩賭上性命的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"외지인이 끼어들 이유는 없다고.","JPN":"よそ者が巻き込まれる理由はない。","ENG":"There's no reason for an outsider to intervene.","TWN":"外地人沒理由介入。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨에게 부탁받았어요.","JPN":"マーリンさんにお願いされたんです。","ENG":"It was Merlin's request that I do.","TWN":"是梅林拜託我的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"동토 곳곳을 돌아다니는 일이니, 여러분을 도우며 함께 다니면 요정을 찾는 데도 도움이 될 거라면서요.","JPN":"凍土のあちこちを探索する仕事だから、みなさんと協力しながら一緒に行動すれば、妖精を見つける役にたつかもしれないと。","ENG":"She said that since you all traverse the gelid lands, I can help out while I look for the fairy.","TWN":"因為會穿越整個凍土，既可以幫忙大家，我也可以順便尋找精靈。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"핫, 요저엉-?","JPN":"はっ、よーせい？","ENG":"Huh? Fairy?","TWN":"蛤，精靈？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어린애도 아니고 그런 걸 진심으로 찾는 어른이 있단 말이야?","JPN":"子どもじゃあるまいし、そんなものを本気で信じて探す大人なんているの？","ENG":"You're an adult, not a child, but you still believe in fairies?","TWN":"又不是小朋友，有大人會相信這種事嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어린애라뇨. 요정은 진짜예요.","JPN":"子どもだなんて。妖精は本当に存在します。","ENG":"A child? But fairies are real.","TWN":"我才不是小朋友，精靈是真的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"동화뿐만 아니라 역사문헌에도 나오는 존재라고요.","JPN":"童話の中だけでなく、歴史の文献にも出てくるんですから。","ENG":"They are entities recorded in historical records and not just in fairytales.","TWN":"精靈不是只有出現在童話故事裡，也有紀錄在歷史文獻裡。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"세상에 요정은 없어.","JPN":"この世に妖精はいないわ。","ENG":"There are no such things as fairies.","TWN":"世界上沒有精靈。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그렇게 사람 소원을 잘 들어주는 존재가 남아 있다면, 세상이 이지경이 됐는데 수 백 년이나 모습을 안 드러낼 리 없잖아?","JPN":"人の願いを聞いてくれるそんな便利な存在がまだいるなら、世界がこんなことになってるのに、なんで数百年も姿を見せないのよ？","ENG":"If there were beings who granted wishes, they wouldn't have stood by and watched the world wreak havoc for centuries.","TWN":"要是真的有會替人實現願望的精靈，怎麼會幾百年都不現身，放任世界變成現在這樣？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나가 요정을 어떻게 생각하든, 전 따라갈 거예요.","JPN":"モルガナが妖精をどう思っていようが構いません。私はついて行きます。","ENG":"Whatever you think about fairies, Morgana, I'm going with you.","TWN":"不管你怎麼想，我都要去。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};